"use client";

import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";
import * as React from "react";
import { cn } from "@/lib/utils";

/**
 * Brand-tokenised button primitive. Variants:
 *
 *   - `solid`    — primary CTA. `bg-wx-primary` fill, used once per
 *                  surface (Ask a question, Send message, etc.).
 *   - `tonal`    — secondary surface tile. `bg-wx-bg-elevated` fill,
 *                  hover bumps to `bg-wx-bg-elevated-2`. The Home tab's
 *                  "Ask a question" / "Recent message" / News cards
 *                  all use this.
 *   - `ghost`    — chromeless, hover-only background. Inline actions
 *                  inside cards (close button, reaction pills).
 *   - `outline`  — bordered, transparent fill. Rare; reserved for
 *                  destructive confirmations.
 *
 * Sizes use `--wx-radius*` tokens so brand shape (pill vs rounded vs
 * sharp) propagates from operator overrides without per-component
 * surgery.
 */
const buttonVariants = cva(
  // `whitespace-nowrap` was removed from the base — it was forcing
  // wide `tile`-size buttons (Help category cards, Home tab tiles)
  // to grow horizontally to fit multi-line descriptions on a single
  // line, which overflowed the panel on narrow viewports. Single-
  // line buttons (sm / md / lg / icon) re-add nowrap via the size
  // variant below; `tile` deliberately omits it so its content can
  // wrap.
  "inline-flex items-center justify-center gap-2 font-semibold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary focus-visible:ring-offset-2 focus-visible:ring-offset-wx-bg disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        solid: "bg-wx-primary text-wx-primary-fg hover:bg-wx-primary-hover",
        tonal: "bg-wx-bg-elevated text-wx-fg hover:bg-wx-bg-elevated-2",
        ghost: "bg-transparent text-wx-fg-muted hover:bg-wx-bg-elevated hover:text-wx-fg",
        outline: "border border-wx-border bg-transparent text-wx-fg hover:bg-wx-bg-elevated",
      },
      size: {
        sm: "h-8 px-3 text-xs rounded-wx-sm whitespace-nowrap",
        md: "h-10 px-4 text-sm rounded-wx whitespace-nowrap",
        lg: "h-12 px-5 text-sm rounded-wx-lg whitespace-nowrap",
        // `tile` is the giant tap target used on the Home tab — the
        // button IS the card. No `whitespace-nowrap` so its
        // description text wraps inside the panel width.
        tile: "w-full px-5 py-5 text-base rounded-wx-lg",
        icon: "h-9 w-9 rounded-full whitespace-nowrap",
      },
    },
    defaultVariants: { variant: "solid", size: "md" },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return (
      <Comp ref={ref} className={cn(buttonVariants({ variant, size, className }))} {...props} />
    );
  },
);
Button.displayName = "Button";

export { buttonVariants };
