"use client";

import { ApolloClient, type ApolloLink, from, HttpLink, InMemoryCache } from "@apollo/client";
import { setContext } from "@apollo/client/link/context";
import { onError } from "@apollo/client/link/error";
import { apiBase } from "./api";

/**
 * Apollo client for the widget's visitor-facing GraphQL surface
 * (Day 27 backend). Lives at `${apiBase()}/graphql` — same endpoint
 * the operator dashboard uses; isolation comes from resolver-level
 * guards on the BE that check our visitor JWT + integration scope.
 *
 * **Auth state is module-local + mutable** rather than React state
 * so the auth link can stamp every outgoing request without forcing
 * a client recreation. The JWT updates after the auth handshake +
 * on transparent re-auth; updates take effect on the *next* request.
 *
 * **No SSR for queries.** The widget is a client-only surface — the
 * page renders an empty shell, hydrates, then fires queries. RSC
 * data fetching isn't worth the complexity for a chat iframe.
 */

let visitorToken: string | null = null;
let publicKey: string | null = null;

export function setVisitorToken(token: string | null) {
  visitorToken = token;
}

/** Current visitor JWT, or `null`/empty when there's no session yet (e.g.
 *  the `requireAuth` gate hands back an empty anonymous session). Callers
 *  use this to SKIP best-effort, visitor-guarded ops (view tracking) when
 *  there's no token — firing them would 401 and trip the 401-recovery. */
export function getVisitorToken(): string | null {
  return visitorToken;
}

/** Recovery callback fired when a visitor request is rejected with 401
 *  (stale / forged / expired token). `useVisitorAuth` registers a
 *  handler that drops the bad token + re-handshakes — so a bad token
 *  can't leave the widget stuck "verified but can't send / can't log
 *  in". Module-local so the error link can reach it without React. */
let onVisitorUnauthorized: (() => void) | null = null;
export function setOnVisitorUnauthorized(cb: (() => void) | null) {
  onVisitorUnauthorized = cb;
}

/** Recovery callback fired when the BE returns the distinct
 *  `webIntegrationMismatch` code (visitor JWT was minted for a
 *  different integration than the publicKey on the request — happens
 *  when the legacy global localStorage key from before publicKey
 *  scoping is migrated to a DIFFERENT operator's slot on a
 *  cross-operator visitor). Recovery wipes the scoped session for THIS
 *  publicKey and re-handshakes — sharper than the generic 401 path
 *  because we know exactly what went wrong (stops the eager-migration
 *  feedback loop). */
let onVisitorIntegrationMismatch: (() => void) | null = null;
export function setOnVisitorIntegrationMismatch(cb: (() => void) | null) {
  onVisitorIntegrationMismatch = cb;
}

/** The auth handshakes don't carry a visitor token (they mint one), so
 *  a 401 from them is NOT a stale-token signal — skip recovery to avoid
 *  a re-handshake loop. */
const AUTH_HANDSHAKE_OPS = new Set([
  "StartAnonymousVisitor",
  "StartIdentifiedVisitor",
  "VisitorPasskeyRegistrationOptions",
  "VerifyVisitorPasskeyRegistration",
  "VisitorPasskeyAuthenticationOptions",
  "VerifyVisitorPasskeyAuthentication",
]);

export function setPublicKey(key: string | null) {
  publicKey = key;
}

/** Read the current publicKey — used by non-Apollo transports (the
 *  SSE realtime stream) that need to attach it to the URL because
 *  `EventSource` can't set custom headers. */
export function getPublicKey(): string | null {
  return publicKey;
}

let cachedClient: ApolloClient | null = null;

export function getApolloClient(): ApolloClient {
  if (cachedClient) return cachedClient;

  const httpLink = new HttpLink({
    uri: `${apiBase()}/graphql`,
    credentials: "omit",
  });

  const authLink: ApolloLink = setContext((_, { headers }) => {
    return {
      headers: {
        ...headers,
        ...(publicKey ? { "x-web-public-key": publicKey } : {}),
        ...(visitorToken ? { authorization: `Bearer ${visitorToken}` } : {}),
      },
    };
  });

  // Recover from a stale / forged / expired visitor token: a 401 on any
  // NON-handshake request means the token is bad — hand off to the
  // registered recovery (drop the token + re-handshake → sign-in gate),
  // so a tampered `wexio:visitor-session` can't strand the widget in a
  // "verified but every request 401s, no way to re-login" state.
  const errorLink = onError(({ operation, graphQLErrors, networkError }) => {
    if (AUTH_HANDSHAKE_OPS.has(operation.operationName)) return;
    const netStatus =
      networkError && "statusCode" in networkError
        ? (networkError as { statusCode?: number }).statusCode
        : undefined;
    // The BE emits a distinct code when a JWT issued for integration A
    // is presented with integration B's publicKey — sharper than a
    // generic 401 because we know to wipe this publicKey's scoped
    // session storage (the eager migration in `ensureVisitorId` /
    // `readPersistedIdentifiedSession` can copy a wrong-integration
    // token from the legacy global key on a visitor's first cross-
    // operator visit; this is the self-heal for that case).
    const isIntegrationMismatch = (graphQLErrors ?? []).some((e) => {
      const ext = e.extensions as { code?: string; response?: { message?: unknown } } | undefined;
      if (ext?.code === "webIntegrationMismatch") return true;
      // Nest's BadRequest envelopes nest the validator message under
      // `extensions.response.message` — accept either shape.
      const msg = ext?.response?.message;
      if (typeof msg === "string" && msg.includes("webIntegrationMismatch")) return true;
      if (
        Array.isArray(msg) &&
        msg.some((m) => typeof m === "string" && m.includes("webIntegrationMismatch"))
      )
        return true;
      return false;
    });
    if (isIntegrationMismatch) {
      onVisitorIntegrationMismatch?.();
      return;
    }
    const is401 =
      netStatus === 401 ||
      (graphQLErrors ?? []).some((e) => {
        const ext = e.extensions as
          | { code?: string; response?: { statusCode?: number } }
          | undefined;
        return (
          ext?.code === "UNAUTHENTICATED" ||
          ext?.response?.statusCode === 401 ||
          e.message === "Unauthorized"
        );
      });
    if (is401) onVisitorUnauthorized?.();
  });

  cachedClient = new ApolloClient({
    link: from([errorLink, authLink, httpLink]),
    cache: new InMemoryCache({
      // The visitor surface is read-heavy + low cardinality (one
      // visitor, one chat, a handful of help articles); aggressive
      // caching is fine. Day 2+ can tighten typePolicies once we see
      // real query shapes.
      typePolicies: {},
    }),
    defaultOptions: {
      // `cache-first` for watchQuery too — the visitor surface is
      // read-heavy and the data the widget cares about (help
      // articles, news posts, folder trees, reaction palettes) is
      // stable across a single session. Without this, every tab
      // re-visit fires a refetch ("cache-and-network" default),
      // which the visitor sees as needless network noise. Surfaces
      // that need fresh-on-mount (chat history) opt in explicitly
      // via the per-query `fetchPolicy`.
      watchQuery: { errorPolicy: "all", fetchPolicy: "cache-first" },
      query: { errorPolicy: "all", fetchPolicy: "cache-first" },
      mutate: { errorPolicy: "all" },
    },
  });

  return cachedClient;
}
