/**
 * Demo-mode help content (categories + articles). Surfaced when the
 * widget runs with `forceDummyData` / `mode=demo` — see
 * `lib/use-widget-env.tsx`.
 *
 * Structure (ids, slug, category, counts, dates) lives here; the
 * translatable text (title, excerpt, markdown body) comes from the
 * `demo.help.*` next-intl namespace (both locales), read via `t.raw()`.
 * See `dummy/translator.ts`.
 */

import { authorsFor, type DemoAuthorKey } from "./authors";
import type { DemoTranslator } from "./translator";

// ─── Categories ─────────────────────────────────────────────────────

export interface MockHelpCategory {
  id: string;
  title: string;
  description: string;
  articleCount: number;
}

const CATEGORY_IDS = [
  "demo-cat-getting-started",
  "demo-cat-automation",
  "demo-cat-integrations",
  "demo-cat-billing",
] as const;

export function getMockHelpCategories(t: DemoTranslator): MockHelpCategory[] {
  return CATEGORY_IDS.map((id) => ({
    id,
    // Derived from the real article list so the badge always matches
    // what the visitor sees when they drill in — no more "12" leading
    // to a 2-article folder.
    articleCount: ARTICLE_STRUCT.filter((a) => a.categoryId === id).length,
    title: t.raw(`help.categories.${id}.title`) as string,
    description: t.raw(`help.categories.${id}.description`) as string,
  }));
}

// ─── Articles ───────────────────────────────────────────────────────

export interface MockHelpArticle {
  id: string;
  slug: string;
  title: string;
  excerpt: string;
  categoryId: string;
  viewCount: number;
  publishedAt: string;
  contentMarkdown: string;
  authors: { _id: string; name: string; photo: { url: string } }[];
  tags: { _id: string; slug: string; label: string }[];
  /** Optional mock reaction counts keyed by slot index. */
  reactionCounts?: Record<string, number>;
}

/** Structure (locale-independent). `authorIds` reference `DEMO_AUTHORS`;
 *  `tagSlugs` map to `help.tags.<slug>` labels in the demo i18n bundle. */
type ArticleStruct = Pick<
  MockHelpArticle,
  "id" | "slug" | "categoryId" | "viewCount" | "publishedAt"
> & {
  authorIds: DemoAuthorKey[];
  tagSlugs: string[];
};

