/**
 * Build the demo help articles from the active `demo` translator. Text
 * (title, excerpt, body, tag labels) comes from the `demo.help.*`
 * namespace; authors + tag slugs are locale-independent structure.
 */
export function getMockHelpArticles(t: DemoTranslator): MockHelpArticle[] {
  return ARTICLE_STRUCT.map(({ authorIds, tagSlugs, ...s }) => ({
    ...s,
    title: t.raw(`help.articles.${s.id}.title`) as string,
    excerpt: t.raw(`help.articles.${s.id}.excerpt`) as string,
    contentMarkdown: t.raw(`help.articles.${s.id}.body`) as string,
    authors: authorsFor(authorIds),
    tags: tagSlugs.map((slug) => ({
      _id: `demo-tag-${slug}`,
      slug,
      label: t.raw(`help.tags.${slug}`) as string,
    })),
  }));
}
